function UIMainControl:secondToStr(second)
    if second <= 0 then
        return
    end
    local hour = second / (60 * 60)
    local minute = (second % (60 * 60)) / 60
    return string.format("%02d:%02d", hour, minute)
end

function UIMainControl:updateExchangeReward()
    local player = PlayerManager:getClientPlayer()
    if not player then
        return
    end

    local exchangeReward = player.property.exchangeReward
    local payItemList = player.property.payItemList
    if not exchangeReward or not payItemList then
        return
    end

    if exchangeReward["ConcealPower"] then
        local time = exchangeReward["ConcealPower"] - os.time()
        self.txtPretendTime:SetVisible(time > 0 and not payItemList[tostring(Define.PayItemType.ConcealPower)])
        self.txtPretendTime:SetText(self:secondToStr(time))
    end

    if exchangeReward["AutoWorkout"] then
        local time = exchangeReward["AutoWorkout"] - os.time()
        self.txtSkinTime:SetVisible(time > 0 and not payItemList[tostring(Define.PayItemType.AutoWorkout)])
        self.txtSkinTime:SetText(self:secondToStr(time))
    end

    if exchangeReward["DoubleSpeed"] then
        local time = exchangeReward["DoubleSpeed"] - os.time()
        self.layDoubleSpeed:SetVisible(time > 0 and not payItemList[tostring(Define.PayItemType.DoubleSpeed)])
        self.txtDoubleSpeedTime:SetText(self:secondToStr(time))
    end

    if exchangeReward["DoubleMuscle"] then
        local time = exchangeReward["DoubleMuscle"] - os.time()
        self.layDoubleMuscle:SetVisible(time > 0 and not payItemList[tostring(Define.PayItemType.DoubleMuscle)])
        self.txtDoubleMuscleTime:SetText(self:secondToStr(time))
    end

    if exchangeReward["DoubleGold"] then
        local time = exchangeReward["DoubleGold"] - os.time()
        self.layDoubleGold:SetVisible(time > 0 and not payItemList[tostring(Define.PayItemType.DoubleGold)])
        self.txtDoubleGoldTime:SetText(self:secondToStr(time))
    end
end

function UIMainControl:onSkillCountClick(i)
    --print("_______________________________")
    local player = PlayerManager:getClientPlayer()
    if not player then
        return
    end
    --print("___________+++++++++++__________")
    if player.property.advancedLevel <= 0 then
        self:showGameTip("gui_skill_lock", 2000)
        return
    end

    if self.skillMap[i] ~= 0 then
        local skill = SkillConfig:getSkillById(self.skillMap[i])
        if skill == nil then
            skill = TokenSkillConfig:getSkillById(self.skillMap[i])
        end
        if skill and skill.skillType ~= Define.SkillType.Common and player:isGrab() == false then
            self:showGameTip("gui_skill_not_grad", 2000)
        end
    end

end
function UIMainControl:onSkillIconClick(i)
    if self.autoWorkout then
        return
    end

    if self.isSkillCd[i] > os.time() or self.isSkillCdTime[i] then
        return
    end

    MainControlController:onSkillIconClick(i)
end

function UIMainControl:onSkillGrab()
    if self.autoWorkout or self.isAttackCd then
        return
    end

    if self.isSkillCd[4] > os.time() or self.isSkillCdTime[4] then
        return
    end

    MainControlController:onSkillGrab()
end

function UIMainControl:initEvent()
    --更新血量
    self:registerEvent(HpChangeEvent, function(curHealth, maxHealth)
        self:onHpUpdate(curHealth, maxHealth)
    end)

    --更新肌肉值
    self:registerEvent(MuscleMassChangeEvent, function(muscleMass, maxMuscleMass, inc)
        self:onMpUpdate(muscleMass, maxMuscleMass, inc)
    end)

    --更新器材
    self:registerEvent(FitnessEquipChangeEvent, function(fitnessEquipId, unlockFitnessEquipId)
        self:onEquipUpdate(fitnessEquipId, unlockFitnessEquipId)
    end)

    --更新技能
    self:registerEvent(S2CLSEquipmentOrUnloadSkill, function(data)
        self:onSkillUpdate(data)
    end)

    self:registerEvent(PayDataInitEvent, function(payItemList, skinList)
        if payItemList and payItemList[Define.PayItemType.InfinityMuscle] ~= 0 then
            local player = PlayerManager:getClientPlayer()
            self:onMpUpdate(player.property.muscleMass, player.property.maxMuscleMass, 0)
        end
    end)

    --肌肉值旁边按钮点击
    self.btnMpClick:registerEvent(GUIEvent.ButtonClick, function()
        self:onMpClick(true)
    end)

    --Button选择状态
    self.ivEquipIcon:registerEvent(GUIEvent.Click, function()
        if self.selectMode == Define.SelectMode.Equip then
            return
        end
        self:onButtonSelect(Define.SelectMode.Equip)
    end)
    self.ivPunchIcon:registerEvent(GUIEvent.Click, function()
        if self.selectMode == Define.SelectMode.Punch then
            return
        end
        self:onButtonSelect(Define.SelectMode.Punch)
    end)
    self.ivStepIcon:registerEvent(GUIEvent.Click, function()
        if self.selectMode == Define.SelectMode.Step then
            return
        end
        self:onButtonSelect(Define.SelectMode.Step)
    end)

    self.ivPretend:registerEvent(GUIEvent.Click, function()
        self:onClickPretend()
    end)

    self.ivSkin:registerEvent(GUIEvent.Click, function()
        self:onClickSkin()
    end)

    self.ivVip:registerEvent(GUIEvent.Click, function()
        self:onClickVip()
    end)

    self.ivWorkout:registerEvent(GUIEvent.Click, function()
        self:onClickWorkout()
    end)

    self.btnOpenAdvance:registerEvent(GUIEvent.ButtonClick, function()
        local isBeGrab = PlayerManager:getClientPlayer():isBeGrab()
        local player = PlayerManager:getClientPlayer()
        local btnOpenAdvanceEnabled = not self.autoWorkout and not isBeGrab and not player.property.isAdvancing
        if not btnOpenAdvanceEnabled then
            return
        end

        self:onOpenAdvance()

        local data = DataBuilder.new():addParam("ClickAdvance", "nil"):getData()
        PacketSender:sendLuaCommonData("DoReport", data)
    end)

    self:registerEvent(MainControlPretendUpdateEvent, function()
        self:onPretendUpdate()
    end)

    self:registerEvent(S2CMemberUpArrow, function(data)
        self:onMemberUpArrow(data)
    end)

    self:registerEvent(S2CLSAutoWorkoutBack, function(data)
        self:onAutoWorkoutBack(data)
    end)

    self:registerDataCallBack("BossHPInfo", function(data)
        local curHp = math.floor(data:getNumberParam("curHp"))
        local maxHp = math.floor(data:getNumberParam("maxHp"))
        local quantity = data:getNumberParam("quantity")
        self.bossHpInfo.preHp = curHp
        self.bossHpInfo.curHp = curHp
        self.bossHpInfo.maxHp = maxHp
        self.bossHpInfo.subHp = math.floor(maxHp / quantity)
        self.bossHpInfo.quantity = quantity
        self:setBossHpVisible(true)
        table.insert(self.bossHurtCache, { total = 0, subHp = 0, isSub = true })
    end, DataBuilderProcessor)

    self:registerDataCallBack("BossCurHp", function(data)
        local curHp = data:getNumberParam("curHp")
        local damage = self.bossHpInfo.preHp - curHp
        self.bossHpInfo.preHp = curHp
        if damage >= 0 then
            local subHp = math.min(self.bossHpInfo.subHp / 2, damage / 20)
            table.insert(self.bossHurtCache, { total = damage, subHp = subHp, isSub = true })

            local entityId = data:getNumberParam("entityId")
            local entity = EntityCache:getEntityByServerId(entityId)
            if entity then
                Utility.showFloatNumber(entity.entity, nil, damage, 2)
            end
        else
            local subHp = math.max(-self.bossHpInfo.subHp / 2, damage / 20)
            table.insert(self.bossHurtCache, { total = damage, subHp = subHp, isSub = false })
        end
    end, DataBuilderProcessor)

    self:registerDataCallBack("SyncActorDamage", function(data)
        local entityId = data:getNumberParam("entityId")
        local damage = data:getNumberParam("damage")
        local entity = EntityCache:getEntityByServerId(entityId)
        --LogUtil.log(string.format("SyncActorDamage entityId:%d, damage:%d, entity:%s",
        --        entityId, damage, tostring(entity)))
        if entity then
            Utility.showFloatNumber(entity.entity, nil, damage, 3)
        end
    end, DataBuilderProcessor)

    self:registerEvent(ShopAdvancedChangeEvent, function()
        self:onShopAdvancedChange()
    end)

    self:registerEvent(GoldChangeEvent, function(bigNum)
        --print("++++++++++++++++++++")
        --self:onGoldChange(bigNum)
        self:onShopAdvancedGoldChange(bigNum)
    end)

    self:registerEvent(S2CLSEditionVisibleInfo, function(data)
        self:editionVisibleInfo(data)
    end)

    self:registerDataCallBack("AutoWorkAd", function(data)
        local type = data:getNumberParam("type")
        local id = data:getNumberParam("id")
        local waitTime = data:getNumberParam("waitTime")
        local duration = data:getNumberParam("duration")
        local count = data:getNumberParam("count")
        self.workoutAdInfo.type = type
        self.workoutAdInfo.id = id
        self.workoutAdInfo.waitTime = waitTime
        self.workoutAdInfo.duration = duration
        self.workoutAdInfo.count = count
        if waitTime > 0 then
            LuaTimer:scheduleTimer(function()
                if self.workoutAdInfo.waitTime <= 0 then
                    return
                end
                self.workoutAdInfo.waitTime = self.workoutAdInfo.waitTime - 1
                if self.workoutAdInfo.waitTime == 0 then
                    self:updateAdvertUI()
                end
            end, 1000, waitTime)
        end
        if duration > 0 then
            LuaTimer:scheduleTimer(function()
                if self.workoutAdInfo.duration <= 0 then
                    return
                end
                self.workoutAdInfo.duration = self.workoutAdInfo.duration - 1
            end, 1000, duration)
        end
        self:updateAdvertUI()
    end, DataBuilderProcessor)

    self.btnShop:registerEvent(GUIEvent.ButtonClick, function()
        GUIShop:showShop()
    end)

    self.btnChampionShip:registerEvent(GUIEvent.ButtonClick, function()

        local player = PlayerManager:getClientPlayer()
        if player.property.advancedLevel < GameConfig.btnChampionShipEnableLevel then
            self:showGameTip("gui_championship_btn_limit", 2000)
            return
        end
        if player.property.isAdvancing then
            return
        end

        ToolBarSeasonRankClickEvent:invoke()
    end)
end

function UIMainControl:editionVisibleInfo(data)

    local builder = DataBuilder.new():fromData(data)
    local isVisible = builder:getBoolParam("isVisible")
    self.ivVip:SetVisible(isVisible)
    self.ivSkinEffect:SetVisible(isVisible)

end

function UIMainControl:onOpenAdvance()
    if self.currAdvanced == nil then
        return
    end

    if self.currAdvanced.Status == ItemBuyStatus.Buy then
        local listener = function()
            local data = {
                Kind = TabKind.Advanced,
                ItemId = self.currAdvanced.Id
            }
            local builder = DataBuilder.new():fromTable(data):getData()
            PacketSender:sendLuaCommonData("ShopButtonClick", builder)
        end
        CustomDialog.builder()
                    .setContentText(Lang:getString(self.currAdvanced.Tips))
                    .setRightClickListener(listener)
                    .show()
        return
    end

    if self.currAdvanced.Status == ItemBuyStatus.Unlock then
        if self.goldNum >= self.currAdvanced.Price then
            local listener = function()
                local data = {
                    Kind = TabKind.Advanced,
                    ItemId = self.currAdvanced.Id
                }
                local builder = DataBuilder.new():fromTable(data):getData()
                PacketSender:sendLuaCommonData("ShopButtonClick", builder)
            end

            CustomDialog.builder()
                        .setContentText(Lang:getString(self.currAdvanced.BuyTips))
                        .setRightClickListener(listener)
                        .show()

        else
            local tab = TabsConfig:getTabsById(3) -- 临时方案 进阶是3 后期修改需求的
            GUIShop:show()
            GUIShop:onClickTab(tab.Id, tab.Type)
            GUIShop:onClickAdvanceItem(self.currAdvanced.Id)
        end
    end

    if self.currAdvanced.Status == ItemBuyStatus.Used then
        local tab = TabsConfig:getTabsById(3) -- 临时方案 进阶是3 后期修改需求的
        GUIShop:show()
        GUIShop:onClickTab(tab.Id, tab.Type)
    end
end

function UIMainControl:onShopAdvancedGoldChange(bigNum)
    self.goldNum = tonumber(tostring(bigNum))
    --self.goldNum = bigNum

    if self.currAdvanced == nil then
        return
    end
    if self.goldNum > GameConfig.guideShopGold then
        GuideSystemSetting.onGuideTriggered(107)
    end
    self.pbAdvanceGoldPg:SetProgress(self.goldNum / (self.currAdvanced.Price or 0))
    local strGoldNum = Utility.toKMBString(tostring(self.goldNum), 2)
    local strAdvanceGold = Utility.toKMBString(tostring(self.currAdvanced.Price), 2)
    local strAdvanceGoldNum = strGoldNum .. "/" .. strAdvanceGold
    self.tvAdvanceGoldNum:SetText(strAdvanceGoldNum)
end

function UIMainControl:onShopAdvancedChange()
    table.sort(AdvancedConfig:getAdvanceds(), function(a, b)
        return a.Id < b.Id
    end)

    for _, advanced in pairs(AdvancedConfig:getAdvanceds()) do
        if advanced.Status == ItemBuyStatus.Unlock or advanced.Status == ItemBuyStatus.Buy or advanced.Status == ItemBuyStatus.Used then
            self.currAdvanced = advanced
        end
    end
    if self.currAdvanced == nil then
        return
    end

    self.btnOpenAdvanceIcon:SetImage(self.currAdvanced.Icon)
    if self.currAdvanced.Status == ItemBuyStatus.Unlock then
        --
        self.ivAdvanceGoldBg:SetVisible(true)
        self:onShopAdvancedGoldChange(self.goldNum)
        self.ivAdvanceBuySuccessBg:SetVisible(false)
    elseif self.currAdvanced.Status == ItemBuyStatus.Buy then
        self.ivAdvanceGoldBg:SetVisible(false)
        self.ivAdvanceBuySuccessBg:SetVisible(true)
