function UIMainControl:onClickWorkout()
    LuaTimer:cancel(MainControlController.grabTimer)
    LogUtil.log("UIMainControl:onClickWorkout LuaTimer:cancel " .. tostring(MainControlController.grabTimer))

    --print("++++++++++++++++++++++++++++++")
    local onePrivilege = PayItemConfig:getPayItemByType(Define.PayItemType.AutoWorkout)
    --print(json.encode(onePrivilege))
    if onePrivilege and onePrivilege.Status == PayItemBuyStatus.Buy and self.workoutAdInfo.duration <= 0
            and not PlayerManager:getClientPlayer().property:hasPayItem(Define.PayItemType.AutoWorkout) then

        local sureListener = function()
            LuaTimer:schedule(function()
                MainControlCustomDialogClickEvent:invoke(PayTabKind.Privilege, onePrivilege.Id)
            end, 0)

            local data = DataBuilder.new():addParam("ClickWorkout", "sure"):getData()
            PacketSender:sendLuaCommonData("DoReport", data)
        end

        local cancelListener = function()
            if self.isHaveAd and self.workoutAdInfo.type ~= 0 then
                --有广告
                if self.workoutAdInfo.waitTime <= 0 then
                    --看广告
                    ClientHelper.onWatchAd(self.workoutAdInfo.type, tostring(self.workoutAdInfo.id))
                    --增加无敌状态
                    local params = {
                        Time = 35 --35秒
                    }
                    local data = DataBuilder.new():fromTable(params):getData()
                    PacketSender:sendLuaCommonData("AddInvincibleState", data)
                    local data = DataBuilder.new():addParam("ClickWatchAd", "nil"):getData()
                    PacketSender:sendLuaCommonData("DoReport", data)
                else
                    ---冷却时间还没到就点击了看广告
                    return true ---不关闭页面
                end
            else
                local data = DataBuilder.new():addParam("ClickWorkout", "cancel"):getData()
                PacketSender:sendLuaCommonData("DoReport", data)
            end
        end

        local closeListener = function()
            local data = DataBuilder.new():addParam("ClickWorkout", "cancel"):getData()
            PacketSender:sendLuaCommonData("DoReport", data)
        end

        CheckMoneyContent:setCurrencyInfo(PayHelper.getMoneyIcon(MoneyType.Diamonds), onePrivilege.Price)
        CheckMoneyContent:setContentText(Lang:getString("gui_auto_workout_point"))
        CheckMoneyContent:setCurrencyTip(Lang:getString("gui_auto_workout_tip"))
        CheckMoneyContent:setCurrencyNum(tostring(onePrivilege.Price) .. Lang:getString("gui_auto_workout_text"))
        CustomDialog.builder()
                    .setContentView(CheckMoneyContent)
                    .setRightClickListener(sureListener)
                    .setLeftClickListener(cancelListener)
                    .setCloseClickListener(closeListener)
                    .setCustomParams("BuyWorkout")
                    .show()

        --CustomDialog.builder()
        --            .setContentText(Lang:getString("gui_auto_workout_tips"))
        --            .setExtraInfo(PayHelper.getMoneyIcon(MoneyType.Diamonds),Lang:getString("gui_auto_workout_tips"))
        --            .setLeftText(Lang:getString("gui_dialog_tip_btn_cancel"))
        --            .setRightClickListener(listener)
        --            .show()
        --print(string.format("gui_muscle_full_tips %d %d", player.property.muscleMass, player.property.maxMuscleMass))
        return
    end

    self:onClickWorkoutCd()
end

function UIMainControl:onClickWorkoutCd()
    if os.time() - self.AutoWorkoutClickTime > 5 then
        --print("++++++++++++++++++++++++++")
        if self.AutoWorkoutMode == Define.AutoWorkoutSelectMode.NotSelect then
            --print("++++++++++++++++++++++++++++++++++")
            self.AutoWorkoutMode = Define.AutoWorkoutSelectMode.Select
            PacketSender:sendLuaCommonData("TeleAutoWorkout", "")

        else
            --print("??????????????????????????????????")
            self.AutoWorkoutMode = Define.AutoWorkoutSelectMode.NotSelect
            self.workoutAdInfo.duration = 0
            PacketSender:sendLuaCommonData("TeleAutoWorkoutBack", "")
        end
        self.AutoWorkoutClickTime = os.time()
        self.ivWorkoutMask:SetVisible(true)
        self.ivWorkoutMask:setCooldownAnim(true, 5000)
        LuaTimer:schedule(function()
            self.ivWorkoutMask:SetVisible(false)
        end, 5000)
    end
end

