function UIMainControl:onTick()
    if not self:isLoad() then
        return
    end

    --if Platform.isWindow() and os.time() - self.lastHUTime >= 1 then
    --    HU.Update()
    --    self.lastHUTime = os.time()
    --end

    local player = PlayerManager:getClientPlayer()

    local isBeGrab = player:isBeGrab()
    local isGrab = player:isGrab()
    local isAlive = player:isEntityAlive()
    self:updateSkillIcon(player.property.canAttack and isAlive and not isBeGrab and player.property.advancedLevel > 0)
    self:enableAttackUI(player.property.canAttack and isAlive and not isBeGrab)
    self:enableWorkoutUI(player.property.canWorkout and isAlive and not isBeGrab and not isGrab)
    self.btnMpClick:SetEnabled(isAlive and not isBeGrab and not player.property.isAdvancing)
    self.ivWorkout:SetEnabled(not player.property.isAdvancing and not isBeGrab)
    local btnOpenAdvanceEnabled = not self.autoWorkout and not isBeGrab and not player.property.isAdvancing
    self.btnOpenAdvanceIcon:SetEnabled(btnOpenAdvanceEnabled)
    self.btnShop:SetEnabled(btnOpenAdvanceEnabled)
    self.btnChampionShip:SetVisible(player.property.advancedLevel >= GameConfig.btnChampionShipShowLevel)
    --self.btnChampionShip:SetEnabled(player.property.advancedLevel >= GameConfig.btnChampionShipEnableLevel
            --and player.property.muscleMass >= GameConfig.btnChampionShipEnableMuscle and not player.property.isAdvancing)

    self.btnChampionShip:SetEnabled(not player.property.isAdvancing)
    self.btnChampionShip:setGray(player.property.isAdvancing or player.property.advancedLevel < GameConfig.btnChampionShipEnableLevel)
    

    if self.autoWorkout and isAlive then
        MainControlController:onClickScene(true)
    end

    --self.llSkillLayout:SetVisible(player.property.advancedLevel > 0)
    for i = 1, 4 do
        self.skillBg[i]:SetEnabled(player.property.advancedLevel > 0)
    end
    self.ivSkillLock:SetVisible(player.property.advancedLevel <= 0)
    --self.skillIcon[4]:SetEnabled(player.property.advancedLevel > 0)
    --print("|||||||||||||||||||||||||||||||")
    self.llJumpControls:SetArea({ 0, 10000 }, { 0, -310 }, { 0, 84 }, { 0, 220 })
    self.ivJumpButton:SetArea({ 0, 0 }, { 0, 0 }, { 0, 80 }, { 0, 80 })
    --print("<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<")
    self.ivJumpButton:SetAlpha(1)

    self:changeGrabPicture()
    self:updateBossHpUI()
    self:updateExchangeReward()

    if CustomDialog.isShow() then
        local params = CustomDialog.getCustomParams()
        if not params then
            return
        end
        if params == "BuyWorkout" then
            local isHaveWorkoutAd = self.workoutAdInfo.type ~= 0
            if self.isHaveAd and isHaveWorkoutAd then
                CustomDialog.setLeftIcon("set:advert.json image:ad_icon").setLeftIconArea({ 0, 15 }, { 0, 0 }, { 0, 63 }, { 0, 46 })
                if self.workoutAdInfo.waitTime > 0 then
                    local strCount = Lang:getString("workout.advert.count")
                    strCount = strCount .. string.format("(%s)", tostring(self.workoutAdInfo.waitTime))
                    CustomDialog.setLeftText(strCount).setLeftDisable(false)
                else
                    local strFree = Lang:getString("workout.advert.free")
                    strFree = strFree .. string.format("(%s)", tostring(self.workoutAdInfo.count))
                    CustomDialog.setLeftText(strFree)
                end
            end
        end
    end

    if self.workoutAdInfo.duration > 0 then
        self.tvWorkoutBackTime:SetVisible(true)
        self.tvWorkoutBackTime:SetText(tostring(self.workoutAdInfo.duration))
    else
        self.tvWorkoutBackTime:SetVisible(false)
    end

    if self.currAdvanced and self.currAdvanced.Status == ItemBuyStatus.Unlock and self.goldNum >= self.currAdvanced.Price then
        self.ivAdvanceEffect:SetVisible(true)
    else
        self.ivAdvanceEffect:SetVisible(false)
    end

    local showAd = ClientHelper.getBoolPrefs("ShowVideoAd")
    self.isHaveAd = showAd
    self:updateAdvertUI()

end

--用于传送到肌肉售卖区
function UIMainControl:onMpClick(isCd)
    if not self:isLoad() then
        return
    end

    local player = PlayerManager:getClientPlayer()
    if player == nil then
        return
    end
    if os.time() - self.MpClickTime > 5 and isCd then

        if player:isGrab() then
            PacketSender:getSender():sendUnbindEntity(player.property.catchEntityId)
        end

        local params = {
            Area = "SellArea"
        }
        local data = DataBuilder.new():fromTable(params):getData()
        PacketSender:sendLuaCommonData("TeleportToArea", data)

        self.ivMpClickMask:SetVisible(true)
        self.ivMpClickMask:setCooldownAnim(true, 5000)
        LuaTimer:schedule(function()
            self.ivMpClickMask:SetVisible(false)
        end, 5000)
        self.MpClickTime = os.time()

    end
    if isCd == false then

        if player:isGrab() then
            PacketSender:getSender():sendUnbindEntity(player.property.catchEntityId)
        end

        local params = {
            Area = "SellArea"
        }
        local data = DataBuilder.new():fromTable(params):getData()
        PacketSender:sendLuaCommonData("TeleportToArea", data)

    end

end


--用于显示选中状态改变
function UIMainControl:onButtonSelect(flag, force)
    if not self:isLoad() then
        return
    end

    if self.autoWorkout then
        return
    end

    force = force or false
    if self.isAttackCd and not force then
        return
    end

    --取消选中状态
    if flag == self.selectMode then
        self.ivEquipEffect:SetVisible(false)
        self.ivPunchEffect:SetVisible(false)
        self.ivStepEffect:SetVisible(false)
        self.ivEquipBg:SetImage("set:LiftingSimulatorMainControl1.json image:fitnessEquip1")
        self.ivPunchIcon:SetImage("set:LiftingSimulatorMainControl1.json image:punch2")
        self.ivStepIcon:SetImage("set:LiftingSimulatorMainControl1.json image:step2")
        self.selectMode = Define.SelectMode.NotSelect
        MainControlController:doButtonSelect(self.selectMode)
        return
    end

    if flag == Define.SelectMode.Equip then
        self.ivEquipEffect:SetVisible(true)
        self.ivPunchEffect:SetVisible(false)
        self.ivStepEffect:SetVisible(false)
        self.ivEquipBg:SetImage("set:LiftingSimulatorMainControl1.json image:fitnessEquip2")
        self.ivPunchIcon:SetImage("set:LiftingSimulatorMainControl1.json image:punch2")
        self.ivStepIcon:SetImage("set:LiftingSimulatorMainControl1.json image:step2")
        ClientHelper.putStringPrefs("RunSkillName", "wwe_walk")
    elseif flag == Define.SelectMode.Punch then
        self.ivEquipEffect:SetVisible(false)
        self.ivPunchEffect:SetVisible(true)
        self.ivStepEffect:SetVisible(false)
        self.ivEquipBg:SetImage("set:LiftingSimulatorMainControl1.json image:fitnessEquip1")
        self.ivPunchIcon:SetImage("set:LiftingSimulatorMainControl1.json image:punch1")
        self.ivStepIcon:SetImage("set:LiftingSimulatorMainControl1.json image:step2")
        ClientHelper.putStringPrefs("RunSkillName", "run")
    elseif flag == Define.SelectMode.Step then
        self.ivEquipEffect:SetVisible(false)
        self.ivPunchEffect:SetVisible(false)
        self.ivStepEffect:SetVisible(true)
        self.ivEquipBg:SetImage("set:LiftingSimulatorMainControl1.json image:fitnessEquip1")
        self.ivPunchIcon:SetImage("set:LiftingSimulatorMainControl1.json image:punch2")
        self.ivStepIcon:SetImage("set:LiftingSimulatorMainControl1.json image:step1")
        ClientHelper.putStringPrefs("RunSkillName", "run")
    end

    self.selectMode = flag
    MainControlController:doButtonSelect(flag)
end

function UIMainControl:onHpUpdate(curHealth, maxHealth)
    if not self:isLoad() then
        return
    end

    self.pbHpValue:SetProgress(curHealth / maxHealth)

    local strHpNumber = string.format("%s/%s", Utility.toKMBString(tostring(curHealth), 2),
            Utility.toKMBString(tostring(maxHealth), 2))
    self.tvHpNumber:SetText(strHpNumber)

    --print(string.format("UIMainControl:onHpUpdate %s %s", tostring(curHealth), tostring(maxHealth)))
end

function UIMainControl:onMpUpdate(muscleMass, maxMuscleMass, inc)
    if not self:isLoad() then
        return
    end

    if muscleMass > GameConfig.guideSellMuscleMass then
        GuideSystemSetting.onGuideTriggered(106)
    end

    if muscleMass == 0 then
        GuideSystemSetting.onGuideDone(106)
    end

    self.pbMpValue:SetProgress(muscleMass / maxMuscleMass)

    local strMuscleMass = Utility.toKMBString(string.format("%f", muscleMass), 4)
    local strMaxMuscleMass = Utility.toKMBString(string.format("%f", maxMuscleMass), 4)
    --print(strMaxMuscleMass)
    local strMpNumber = strMuscleMass .. "/" .. strMaxMuscleMass

    self.tvMpNumber:SetText(strMpNumber)

    if muscleMass >= maxMuscleMass then
        LogUtil.log("UIMainControl:onMpUpdate GUIMainControl:showMuscleFullTips")
        self:showMuscleFullTips()
    end

    --print(string.format("UIMainControl:onMpUpdate %s %s %s",
    --        tostring(BigNum.new(muscleMass)), tostring(BigNum.new(maxMuscleMass)), tostring(BigNum.new(inc))))
end

function UIMainControl:onEquipUpdate(fitnessEquipId, unlockFitnessEquipId)
