function UIMainControl:showMuscleFullTips()
    local player = PlayerManager:getClientPlayer()
    if not player.property.isInit
            or player.property.muscleMass < player.property.maxMuscleMass
            or player.property.muscleMass <= 0
            or tostring(player.property.maxMuscleMass) == "inf" then
        LogUtil.log(string.format("UIMainControl:showMuscleFullTips not PlayerManager:getClientPlayer().property.isInit %d %d",
                player.property.muscleMass, player.property.maxMuscleMass))
        return
    end

    if RootGuiLayout.Instance():isLayoutShow(2) then
        return
    end

    local rightClickListener = function()
        self:onMpClick(false)
    end

    local closeListener = function()
        --TODO
    end

    CustomDialog.builder()
                .setContentText(Lang:getString("gui_muscle_full_tips"))
                .setRightClickListener(rightClickListener)
                .setLeftClickListener(closeListener)
                .setCloseClickListener(closeListener)
                .show()
    --print(string.format("gui_muscle_full_tips %d %d", player.property.muscleMass, player.property.maxMuscleMass))
end

