function UIMainControl:showSkillCd(visible, cd)
    cd = cd or 0

    for i = 1, 4 do
        --local strSkillMask = string.format("LiftingSimulatorMainControl-Skill%d-Mask", i)
        --self.skillMask[i] = self:getChildWindow(strSkillMask, GUIType.StaticImage)
