function UIMainControl:onSkillCd(cdTime, index)


    --print("|||||||||||||||||||||||||||||||||")
    --print(cdTime)
    --print(index)
    --print("|||||||||||||||||||||||||||||||||")

    for i = 1, 4 do
        if i ~= index then
            if self.isSkillCd[i] < os.time() + cdTime then
                self.isSkillCdTime[i] = true
                self.isSkillCd[i] = os.time() + cdTime
                self.skillMask[i]:SetVisible(true)
                self.skillMask[i]:setCooldownAnim(true, cdTime * 1000)
                LuaTimer:scheduleTimer(function()
                    self.isSkillCdTime[i] = false
                    self.skillMask[i]:SetVisible(false)
                end, cdTime * 1000, 1)
            end
        end
    end

    if (index ~= 4 or index ~= nil) and (index >= 1 and index <= 3) then
        local skill = SkillConfig:getSkillById(self.skillMap[index])
        if skill == nil then
            skill = TokenSkillConfig:getSkillById(self.skillMap[index])
        end
        if skill and self.isSkillCd[index] < os.time() + skill.Cd then
            self.isSkillCdTime[index] = true
            self.isSkillCd[index] = os.time() + skill.Cd
            self.skillMask[index]:SetVisible(true)
            self.skillMask[index]:setCooldownAnim(true, skill.Cd * 1000)
            LuaTimer:scheduleTimer(function()
                self.isSkillCdTime[index] = false
                self.skillMask[index]:SetVisible(false)
            end, skill.Cd * 1000, 1)
        end
    elseif index == 4 and self.isSkillCd[index] < os.time() + cdTime then
        self.isSkillCdTime[index] = true
        self.isSkillCd[index] = os.time() + cdTime
        self.skillMask[index]:SetVisible(true)
        self.skillMask[index]:setCooldownAnim(true, cdTime * 1000)
        LuaTimer:scheduleTimer(function()
            self.isSkillCdTime[index] = false
            self.skillMask[index]:SetVisible(false)
        end, cdTime * 1000, 1)
    end

    --self.isSkillCd = true
    --self:showSkillCd(true, cdTime)
    --
    --LuaTimer:scheduleTimer(function()
    --    self.isSkillCd = false
    --    self:showSkillCd(false, 0)
    --end, cdTime, 1)

end

function UIMainControl:onSkillUpdate(data)
    local builder = DataBuilder.new():fromData(data)
    local id = builder:getNumberParam("id")
    local position = builder:getNumberParam("position")
    local isUnload = builder:getBoolParam("isUnload")

    if position == nil or position < 1 or position > 3 then
        return
    end

    if isUnload then
        --卸载
        self.skillMap[position] = 0
        self.skillIcon[position]:SetImage("")
    else
        --装上
        self.skillMap[position] = id
        local skill = SkillConfig:getSkillById(id)
        if skill == nil then
            skill = TokenSkillConfig:getSkillById(id)
        end

        if skill ~= nil then
            self.skillIcon[position]:SetImage(skill.Icon)
        end
    end
end

function UIMainControl:updateSkillIcon(isAllow)

    for i, value in ipairs(self.skillMap) do
        if value ~= 0 then
            local skill = SkillConfig:getSkillById(value)
            if skill == nil then
                skill = TokenSkillConfig:getSkillById(value)
            end
            local player = PlayerManager:getClientPlayer()
            if skill and skill.skillType ~= Define.SkillType.Common and player:isGrab() == false then
                self.skillIcon[i]:SetEnabled(false)
            else
                self.skillIcon[i]:SetEnabled(isAllow)
            end
        else
            self.skillIcon[i]:SetEnabled(isAllow)
        end
    end
end

function UIMainControl:onBossDead()
    self.bossHurtCache = {}
    local damage = self.bossHpInfo.curHp
    local subHp = damage / 50
    table.insert(self.bossHurtCache, { total = damage, subHp = subHp, isSub = true })
end

function UIMainControl:setBossHpVisible(visible)
    self:getChildWindow("LiftingSimulatorMainControl-Boss-Info"):SetVisible(visible)
end

function UIMainControl:updateBossHpUI()
    if #self.bossHurtCache == 0 then
        return
    end

    local cache = self.bossHurtCache[1]
    cache.total = cache.total - cache.subHp
    if cache.isSub then
        if cache.total <= 0 then
            table.remove(self.bossHurtCache, 1)
        end
    else
        if cache.total >= 0 then
            table.remove(self.bossHurtCache, 1)
        end
    end

    self.bossHpInfo.curHp = self.bossHpInfo.curHp - cache.subHp
    local quantity = math.floor(self.bossHpInfo.curHp / self.bossHpInfo.subHp) --剩余血条数量
    local bgIndex = #bossHpBg - (quantity % #bossHpBg)
    local pbIndex = #bossHpBg - ((quantity + 1) % #bossHpBg)
    local hpBg = ""
    local hpPb = bossHpBg[1]
    if quantity ~= 0 then
        hpBg = bossHpBg[bgIndex]
    end
    hpPb = bossHpBg[pbIndex]
    local hp = self.bossHpInfo.curHp % self.bossHpInfo.subHp
    self.pbBossHp:SetProgress(hp / self.bossHpInfo.subHp)
    self.pbBossHp:SetBackImage(hpBg)
    self.pbBossHp:SetProgressImage(hpPb)

    if quantity <= 0 then
        self.tvBossHpNum:SetText("")
    else
        self.tvBossHpNum:SetText(string.format("x%d", quantity))
    end
    if self.bossHpInfo.curHp <= 0 and #self.bossHurtCache == 0 then
        self:setBossHpVisible(false)
    end
end

function UIMainControl:hideWorkoutAdvert()
    self.workoutAdInfo = { type = 0, id = 0, waitTime = 0, duration = 0 }
    self.tvWorkoutBackTime:SetVisible(false)
    self.ivWorkoutAdEffect:SetVisible(false)
end

function UIMainControl:updateAdvertUI()
    if not self.isHaveAd then
        self.ivWorkoutAdEffect:SetVisible(false)
        return
    end
    local isHaveWorkoutAd = self.workoutAdInfo.type ~= 0 and self.workoutAdInfo.waitTime <= 0
    self.ivWorkoutAdEffect:SetVisible(isHaveWorkoutAd)
end

return UIMainControl
